@media (max-width: 768px) {
    /* 手机端样式 */
    .container { width: 95%; }
    nav ul { display: none; } /* 隐藏菜单，改为汉堡菜单 */
    .hero-title { font-size: 24px; }
}

@media (prefers-color-scheme: dark) {
  body {
    background-color: #121212;
    color: white;
  }
}
